  1	import type { FC, ReactNode } from 'react';
  2	import type { FieldValues } from 'react-hook-form';
  3	
  4	import {
  5	  Button,
  6	  ButtonVariant,
  7	  Flex,
  8	  FormGroup,
  9	  type FormGroupProps,
 10	  Icon,
 11	  Tooltip,
 12	} from '@patternfly/react-core';
 13	import { MinusCircleIcon, PlusCircleIcon } from '@patternfly/react-icons';
 14	import { Table, Tbody, Td, Th, Thead, type ThProps, Tr } from '@patternfly/react-table';
 15	
 16	import type { AddButtonType, FieldRow, RemoveButtonType } from './types';
 17	
 18	import './FieldBuilderTable.style.scss';
 19	
 20	type FieldBuilderHeader = Omit<ThProps, 'label'> & FormGroupProps;
 21	
 22	type FieldBuilderTableProps<FormData extends FieldValues> = {
 23	  headers: FieldBuilderHeader[];
 24	  fieldRows: FieldRow<FormData>[];
 25	  addButton: AddButtonType;
 26	  removeButton: RemoveButtonType;
 27	};
 28	
 29	const FieldBuilderTable: FC<FieldBuilderTableProps<FormData>> = ({
 30	  addButton,
 31	  fieldRows,
 32	  headers,
 33	  removeButton,
 34	}) => {
 35	  const totalColSpan = headers.length + 1; // +1 for action column
 36	
 37	  return (
 38	    <Flex direction={{ default: 'column' }} spaceItems={{ default: 'spaceItemsSm' }}>
 39	      <Table
 40	        borders={false}
 41	        className="field-builder-table pf-m-grid-md"
 42	        role="grid"
 43	        variant="compact"
 44	      >
 45	        <Thead>
 46	          <Tr>
 47	            {headers.map((header, headerIndex) => (
 48	              <Th key={headerIndex} width={header.width}>
 49	                <FormGroup {...header} hasNoPaddingTop />
 50	              </Th>
 51	            ))}
 52	            {/* Action column for remove buttons */}
 53	            <Th width={10} />
 54	          </Tr>
 55	        </Thead>
 56	
 57	        <Tbody>
 58	          {fieldRows.reduce<ReactNode[]>((acc, fieldRow, rowIndex) => {
 59	            // Main row containing field inputs and remove button
 60	            const removeButtonTip = removeButton.tooltip?.(rowIndex);
 61	            const button = (
 62	              <Button
 63	                icon={
 64	                  <Icon size="md">
 65	                    <MinusCircleIcon />
 66	                  </Icon>
 67	                }
 68	                isInline
 69	                variant={ButtonVariant.plain}
 70	                isDisabled={removeButton.isDisabled?.(rowIndex)}
 71	                onClick={() => {
 72	                  removeButton.onClick(rowIndex);
 73	                }}
 74	              />
 75	            );
 76	
 77	            acc.push(
 78	              <Tr key={fieldRow.id}>
 79	                {fieldRow.inputs.map((fieldInput) => (
 80	                  <Td key={fieldInput.key}>{fieldInput}</Td>
 81	                ))}
 82	
 83	                {/* Remove button cell */}
 84	                <Td isActionCell>
 85	                  {removeButtonTip ? (
 86	                    <Tooltip content={removeButtonTip}>
 87	                      <span>{button}</span>
 88	                    </Tooltip>
 89	                  ) : (
 90	                    button
 91	                  )}
 92	                </Td>
 93	              </Tr>,
 94	            );
 95	
 96	            // Conditionally add additional options row if it exists
 97	            if (fieldRow.additionalOptions) {
 98	              acc.push(
 99	                <Tr key={`${fieldRow.id}-additional`}>
100	                  <Td colSpan={totalColSpan}>{fieldRow.additionalOptions}</Td>
101	                </Tr>,
102	              );
103	            }
104	
105	            return acc;
106	          }, [])}
107	        </Tbody>
108	      </Table>
109	
110	      <Button
111	        isInline
112	        variant={ButtonVariant.link}
113	        icon={<PlusCircleIcon />}
114	        isDisabled={addButton.isDisabled}
115	        onClick={addButton.onClick}
116	      >
117	        {addButton.label}
118	      </Button>
119	    </Flex>
120	  );
121	};
122	
123	export default FieldBuilderTable;

